const inputItems = $input.all();

let totalRowsImported = inputItems.length;
let emptyRowsRemoved = 0;
let invalidEmailsRemoved = 0;
let invalidPhonesRemoved = 0;
let duplicateRowsRemoved = 0;

const seenEmails = {};
const seenPhones = {};
const cleanedData = [];

function cleanText(value) {
  if (value === null || value === undefined) return "";
  return String(value).trim().replace(/\s+/g, " ");
}

function properCase(value) {
  value = cleanText(value).toLowerCase();
  return value.replace(/\b\w/g, function(char) {
    return char.toUpperCase();
  });
}

function isValidEmail(email) {
  email = cleanText(email).toLowerCase();
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

function cleanPhone(phone) {
  return cleanText(phone).replace(/\D/g, "");
}

function isValidPhone(phone) {
  phone = cleanPhone(phone);
  return /^01\d{9}$/.test(phone);
}

function standardizeDate(value) {
  value = cleanText(value);
  if (!value) return "";

  let date;

  if (/^\d{4}[-/]\d{1,2}[-/]\d{1,2}$/.test(value)) {
    const parts = value.split(/[-/]/);
    date = new Date(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2]));
  } else if (/^\d{1,2}[-/]\d{1,2}[-/]\d{4}$/.test(value)) {
    const parts = value.split(/[-/]/);
    date = new Date(Number(parts[2]), Number(parts[1]) - 1, Number(parts[0]));
  } else {
    date = new Date(value);
  }

  if (isNaN(date.getTime())) return "";

  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, "0");
  const day = String(date.getDate()).padStart(2, "0");

  return year + "-" + month + "-" + day;
}

for (const item of inputItems) {
  const row = item.json;

  let fullName = cleanText(row["Full Name"]);
  let email = cleanText(row["Email"]).toLowerCase();
  let phone = cleanPhone(row["Phone"]);
  let city = cleanText(row["City"]);
  let registrationDate = standardizeDate(row["Registration Date"]);

  if (!fullName || !email || !phone || !city || !registrationDate) {
    emptyRowsRemoved++;
    continue;
  }

  if (!isValidEmail(email)) {
    invalidEmailsRemoved++;
    continue;
  }

  if (!isValidPhone(phone)) {
    invalidPhonesRemoved++;
    continue;
  }

  if (seenEmails[email] || seenPhones[phone]) {
    duplicateRowsRemoved++;
    continue;
  }

  seenEmails[email] = true;
  seenPhones[phone] = true;

  cleanedData.push({
    json: {
      "Customer ID": "CUST-" + String(cleanedData.length + 1).padStart(4, "0"),
      "Full Name": properCase(fullName),
      "Email": email,
      "Phone": phone,
      "City": properCase(city),
      "Registration Date": registrationDate
    }
  });
}

const finalRowCount = cleanedData.length;

cleanedData.push({
  json: {
    "Customer ID": "SUMMARY",
    "Full Name": "Total Rows Imported: " + totalRowsImported,
    "Email": "Rows Removed Empty/Invalid: " + emptyRowsRemoved,
    "Phone": "Duplicate Rows Removed: " + duplicateRowsRemoved,
    "City": "Invalid Emails Removed: " + invalidEmailsRemoved,
    "Registration Date": "Invalid Phones Removed: " + invalidPhonesRemoved + " | Final Row Count: " + finalRowCount
  }
});

return cleanedData;
